#!/usr/bin/env node
/**
 * prep-gem-config.mjs
 *
 * Reads public/data/pipelines.json, oilgas-fields.json, lng-terminals.json
 * (generated by prep-gem-*.mjs scripts) and writes:
 *   src/config/global-pipelines.ts   (replaces hand-curated version)
 *   src/config/global-oilgas-fields.ts (replaces hand-curated version)
 *
 * LNG terminals are folded into global-oilgas-fields.ts as type='terminal'
 * entries — this matches the existing DeckGLMap rendering which already
 * distinguishes terminals (amber) from fields (commodity colours).
 *
 * Usage:
 *   node scripts/prep-gem-config.mjs
 */

import { readFileSync, writeFileSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const ROOT = join(__dirname, '..');

const PIPELINES_JSON   = join(ROOT, 'public/data/pipelines.json');
const FIELDS_JSON      = join(ROOT, 'public/data/oilgas-fields.json');
const TERMINALS_JSON   = join(ROOT, 'public/data/lng-terminals.json');
const OUT_PIPELINES    = join(ROOT, 'src/config/global-pipelines.ts');
const OUT_FIELDS       = join(ROOT, 'src/config/global-oilgas-fields.ts');

// ── Commodity/status mappers ──────────────────────────────────────────────────

function mapPipelineCommodity(c) {
  if (!c) return 'crude';
  const l = c.toLowerCase();
  if (l === 'gas') return 'gas';
  if (l === 'ngl' || l.includes('condensate')) return 'condensate';
  if (l === 'lpg' || l.includes('refin')) return 'refined';
  return 'crude'; // oil, crude, etc.
}

function mapPipelineStatus(s) {
  const l = (s || '').toLowerCase();
  if (l === 'operating') return 'active';
  if (l === 'construction') return 'construction';
  return 'inactive'; // mothballed, idle, shelved, etc.
}

function mapFieldCommodity(ft) {
  const l = (ft || '').toLowerCase();
  if (l === 'gas') return 'gas';
  if (l === 'gas and condensate') return 'condensate';
  if (l === 'oil and gas' || l === 'oil/gas') return 'oil/gas';
  return 'oil';
}

function mapFieldStatus(s) {
  const l = (s || '').toLowerCase();
  if (l === 'operating') return 'active';
  if (l === 'in-development') return 'development';
  return 'inactive';
}

// Derive a display region from the countries string
function regionFromCountries(countries) {
  if (!countries) return 'Global';
  const first = countries.split(',')[0].trim();
  return first || 'Global';
}

// ── Serializer helpers ────────────────────────────────────────────────────────

function esc(s) {
  if (s == null) return 'null';
  return JSON.stringify(String(s));
}

function serializeCoords(path) {
  // Output as compact as possible: [[lon,lat],[lon,lat],...]
  return '[' + path.map(([x, y]) => `[${x},${y}]`).join(',') + ']';
}

// ── Pipeline generator ────────────────────────────────────────────────────────

// For MultiLineString pipelines, select the longest path (by point count) as
// the main trunk. Expanding every segment would produce 170k+ entries; the
// longest path captures the primary route at the zoom levels we care about.
function selectMainPath(paths) {
  if (!paths || paths.length === 0) return null;
  if (paths.length === 1) return paths[0];
  return paths.reduce((best, p) => (p.length > best.length ? p : best), paths[0]);
}

// For a pipeline with many short segments (e.g. a distribution network),
// concatenating the top-N longest paths gives better coverage than just one.
// We cap at 3 paths and only use this when the pipeline has > 5 segments,
// because the coordinate overhead is still manageable for a few key trunks.
function selectRepresentativePaths(paths) {
  if (!paths || paths.length === 0) return [];
  if (paths.length <= 3) return paths.filter(p => p.length >= 2);
  // Sort by length descending, take top 3 longest
  return [...paths]
    .sort((a, b) => b.length - a.length)
    .slice(0, 3)
    .filter(p => p.length >= 2);
}

function buildPipelinesTs(pipelines) {
  const lines = [];
  let entryCount = 0;

  lines.push(`// @ts-nocheck`);
  lines.push(`// AUTO-GENERATED by scripts/prep-gem-config.mjs`);
  lines.push(`// Source: Global Energy Monitor (CC BY 4.0) - globalenergymonitor.org`);
  lines.push(`// ${new Date().toISOString().slice(0, 10)}`);
  lines.push(`// Re-run: node scripts/prep-gem-pipelines.mjs && node scripts/prep-gem-config.mjs`);
  lines.push(`import type { GlobalPipeline } from '@/types';`);
  lines.push('');
  lines.push(`export const GLOBAL_PIPELINES: GlobalPipeline[] = [`);

  for (const p of pipelines) {
    const commodity = mapPipelineCommodity(p.commodity);
    const status    = mapPipelineStatus(p.status);
    const region    = regionFromCountries(p.countries);
    const lengthKm  = p.lengthKm ?? 0;
    const capacity  = p.capacityDesc ?? '';

    const allPaths = p.paths || [];
    // Take up to 3 representative paths (longest trunks) per pipeline
    const selectedPaths = selectRepresentativePaths(allPaths);
    if (selectedPaths.length === 0) continue;

    selectedPaths.forEach((path, idx) => {
      const id = selectedPaths.length > 1 ? `${p.id}-${idx}` : p.id;

      const extra = [];
      if (p.countries)  extra.push(`countries:${esc(p.countries)}`);
      if (p.diameter)   extra.push(`diameter:${esc(p.diameter)}`);
      if (p.startYear)  extra.push(`startYear:${p.startYear}`);
      if (p.wiki)       extra.push(`wiki:${esc(p.wiki)}`);
      if (p.segment)    extra.push(`segment:${esc(p.segment)}`);

      lines.push(
        `  {id:${esc(id)},name:${esc(p.name)},commodity:${esc(commodity)},` +
        `status:${esc(status)},operator:${esc(p.operator||'')},` +
        `region:${esc(region)},lengthKm:${lengthKm},` +
        `capacityDesc:${esc(capacity)},` +
        `coordinates:${serializeCoords(path)}` +
        (extra.length ? ',' + extra.join(',') : '') +
        `},`
      );
      entryCount++;
    });
  }

  lines.push(`];`);
  return { ts: lines.join('\n'), count: entryCount };
}

// ── Fields + Terminals generator ─────────────────────────────────────────────

function buildFieldsTs(fields, terminals) {
  const lines = [];

  lines.push(`// @ts-nocheck`);
  lines.push(`// AUTO-GENERATED by scripts/prep-gem-config.mjs`);
  lines.push(`// Source: Global Energy Monitor (CC BY 4.0) - globalenergymonitor.org`);
  lines.push(`// ${new Date().toISOString().slice(0, 10)}`);
  lines.push(`// Re-run: node scripts/prep-gem-fields.mjs && node scripts/prep-gem-terminals.mjs && node scripts/prep-gem-config.mjs`);
  lines.push(`import type { GlobalOilGasField } from '@/types';`);
  lines.push('');
  lines.push(`export const GLOBAL_OILGAS_FIELDS: GlobalOilGasField[] = [`);

  // Fields
  for (const f of fields) {
    const commodity = mapFieldCommodity(f.fuelType);
    const status    = mapFieldStatus(f.status);
    // Build descriptive notes from available metadata
    const noteParts = [];
    if (f.onshoreOffshore) noteParts.push(f.onshoreOffshore);
    if (f.productionType)  noteParts.push(f.productionType);
    if (f.basin)           noteParts.push(`${f.basin} basin`);
    if (f.discoveryYear)   noteParts.push(`discovered ${f.discoveryYear}`);
    const notes = noteParts.join(' / ') || null;

    const extra = [];
    if (f.subnatUnit)    extra.push(`subnatUnit:${esc(f.subnatUnit)}`);
    if (f.basin)         extra.push(`basin:${esc(f.basin)}`);
    if (f.discoveryYear) extra.push(`discoveryYear:${f.discoveryYear}`);
    if (f.wiki)          extra.push(`wiki:${esc(f.wiki)}`);

    lines.push(
      `  {id:${esc(f.id)},name:${esc(f.name)},type:'field',commodity:${esc(commodity)},` +
      `country:${esc(f.country)},operator:${esc(f.operator||'')},` +
      `capacityDesc:'',status:${esc(status)},lat:${f.lat},lon:${f.lon}` +
      (f.startYear ? `,year:${f.startYear}` : '') +
      (notes ? `,notes:${esc(notes)}` : '') +
      (extra.length ? ',' + extra.join(',') : '') +
      `},`
    );
  }

  // LNG Terminals (folded in as type='terminal')
  for (const t of terminals) {
    const status = t.status.toLowerCase() === 'operating' ? 'active' : 'development';
    const cap    = t.capacityMtpa != null ? `${t.capacityMtpa} mtpa` : '';
    const noteParts = [];
    if (t.facilityType) noteParts.push(t.facilityType === 'export' ? 'Export terminal' : 'Import terminal');
    if (t.floating)     noteParts.push('floating');
    if (t.offshore)     noteParts.push('offshore');
    const notes = noteParts.join(' / ') || null;

    const extra = [];
    if (t.facilityType)   extra.push(`facilityType:${esc(t.facilityType)}`);
    if (t.floating != null) extra.push(`floating:${t.floating}`);
    if (t.offshore != null) extra.push(`offshore:${t.offshore}`);
    if (t.wiki)           extra.push(`wiki:${esc(t.wiki)}`);

    lines.push(
      `  {id:${esc(t.id)},name:${esc(t.name)},type:'terminal',commodity:'gas',` +
      `country:${esc(t.country)},operator:${esc(t.operator||'')},` +
      `capacityDesc:${esc(cap)},status:${esc(status)},lat:${t.lat},lon:${t.lon}` +
      (t.startYear ? `,year:${t.startYear}` : '') +
      (notes ? `,notes:${esc(notes)}` : '') +
      (extra.length ? ',' + extra.join(',') : '') +
      `},`
    );
  }

  lines.push(`];`);
  return lines.join('\n');
}

// ── Main ──────────────────────────────────────────────────────────────────────

async function main() {
  console.log('=== prep-gem-config ===');

  console.log('\nReading JSON files...');
  const pipelines = JSON.parse(readFileSync(PIPELINES_JSON, 'utf8'));
  const fields    = JSON.parse(readFileSync(FIELDS_JSON,    'utf8'));
  const terminals = JSON.parse(readFileSync(TERMINALS_JSON, 'utf8'));

  console.log(`  Pipelines: ${pipelines.length}`);
  console.log(`  Fields: ${fields.length}`);
  console.log(`  Terminals: ${terminals.length}`);

  // Build pipelines TypeScript
  console.log('\nGenerating global-pipelines.ts...');
  const { ts: pipelinesTs, count: pipelineEntryCount } = buildPipelinesTs(pipelines);
  const pipelinesSizeKB = Math.round(Buffer.byteLength(pipelinesTs, 'utf8') / 1024);
  writeFileSync(OUT_PIPELINES, pipelinesTs, 'utf8');
  console.log(`  ${pipelineEntryCount} entries (expanded from ${pipelines.length} features)`);
  console.log(`  Output: ${OUT_PIPELINES} (${pipelinesSizeKB} KB)`);

  // Build fields TypeScript
  console.log('\nGenerating global-oilgas-fields.ts...');
  const fieldsTs = buildFieldsTs(fields, terminals);
  const fieldsSizeKB = Math.round(Buffer.byteLength(fieldsTs, 'utf8') / 1024);
  writeFileSync(OUT_FIELDS, fieldsTs, 'utf8');
  const totalFieldEntries = fields.length + terminals.length;
  console.log(`  ${totalFieldEntries} entries (${fields.length} fields + ${terminals.length} terminals)`);
  console.log(`  Output: ${OUT_FIELDS} (${fieldsSizeKB} KB)`);

  console.log('\nDone!');
}

main().catch(e => { console.error(e); process.exit(1); });
